const fs = require('fs');
const path = require('path');

const folderPath = $input.first().json['Chemin du dossier'].trim();

if (!fs.existsSync(folderPath)) {
  throw new Error('Dossier introuvable : ' + folderPath);
}

const files = fs.readdirSync(folderPath)
  .filter(f => f.toLowerCase().endsWith('.pdf'))
  .map(f => ({
    fileName: f,
    originalPath: path.join(folderPath, f),
    folderPath: folderPath
  }));

if (files.length === 0) {
  throw new Error('Aucun fichier PDF trouvé dans : ' + folderPath);
}

return files.map(f => ({ json: f }));

