const path = require('path');
const items = $input.all();

return items.map(item => {
  let rawPath = item.json['Chemin du dossier'];

  if (rawPath) {
    // path.normalize() convertit automatiquement les / en \ sur Windows et inversement sur Linux !
    item.json['Chemin du dossier'] = path.normalize(rawPath.trim());
  }

  return item;
});

const fs = require('fs');
const os = require('os');

const items = $input.all();
const originalItems = $('Lire les PDFs').all();

return items.map((item, index) => {
  try {
    let response = item.json.output || item.json.response || '';

    // 1. On retire le bloc de réflexion (au cas où tu repasses sur Qwen)
    if (response.includes('</think>')) {
      response = response.split('</think>')[1];
    }

    // 2. NOUVEAUTÉ : On efface les mots parasites que Llama adore rajouter
    response = response.replace(/(Nature exacte|Nature|Sujet principal|Sujet|Date)\s*:/gi, ' ');

    // 3. On nettoie tout pour faire un nom de fichier parfait
    let cleanName = 'document_sans_nom';
    if (response && typeof response === 'string') {
      cleanName = response
        .trim()
        .replace(/[^a-zA-Z0-9_\-àâäéèêëîïôùûüç]/g, '_') // Remplace ce qui n'est pas alphanumérique par des _
        .replace(/_+/g, '_') // Supprime les underscores multiples
        .replace(/^_|_$/g, '') // Enlève les underscores au début et à la fin
        .substring(0, 80); // Limite à 80 caractères
    }

    if (!cleanName || cleanName.length < 3) {
       cleanName = 'document_sans_nom_' + Math.floor(Math.random() * 1000);
    }

    // 4. Vérification de sécurité
    if (!originalItems[index] || !originalItems[index].json.originalPath) {
      throw new Error(`Données d'origine introuvables pour l'élément ${index + 1}.`);
    }

    const originalPath = originalItems[index].json.originalPath;
    const folderPath = originalItems[index].json.folderPath;

    // 5. Construction et renommage
    const newName = cleanName + '.pdf';
    const sep = os.platform() === 'win32' ? '\\\\' : '/';
    const newPath = folderPath.replace(/[\\/\\\\]+$/, '') + sep + newName;

    let finalPath = newPath;
    if (fs.existsSync(newPath)) {
      const timestamp = Date.now() + Math.floor(Math.random() * 1000);
      finalPath = newPath.replace('.pdf', '_' + timestamp + '.pdf');
    }

    fs.renameSync(originalPath, finalPath);

    return {
      json: {
        status: '✅ Renommé avec succès',
        ancienChemin: originalPath,
        nouveauChemin: finalPath,
        nomFichier: newName
      }
    };

  } catch (error) {
    return {
      json: {
        status: '❌ Erreur',
        erreur: error.message
      }
    };
  }
});
